1665 |     function smartJSONParse(jsonString) {
1666 |         try {
1667 |             return JSON.parse(jsonString);
1668 |         } catch (e) {
1669 |             console.warn("Standard JSON parse failed, attempting Robust Auto-Fix...");
1670 |             let fixed = jsonString
1671 |                 // 1. Fix backslashes that aren't part of a valid escape sequence
1672 |                 .replace(/\\(?!["\\/bfnrtu])/g, "\\\\")
1673 |                 // 2. Fix literal newlines inside strings (replace with \n)
1674 |                 .replace(/(\n)/g, (match, p1, offset) => {
1675 |                     // Only replace if we are likely inside a quoted string
1676 |                     const before = jsonString.slice(0, offset);
1677 |                     const quoteCount = (before.match(/"/g) || []).length;
1678 |                     return (quoteCount % 2 === 1) ? "\\n" : "\n";
1679 |                 });
1680 | 
1681 |             try {
1682 |                 const cleanObj = JSON.parse(fixed);
1683 |                 document.getElementById('json-input').value = fixed;
