1911 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
1912 |     function applyLocalPatch(content, ops) {
1913 |         let lines = content.split('\n');
1914 |         let logs = [];
1915 |         let success = true;
1916 | 
1917 |         if (typeof ops === 'string') {
1918 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
1919 |         }
1920 | 
1921 |         ops.forEach(op => {
1922 |             if (op.action === 'comment') return;
1923 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
1924 |             
1925 |             if (op.action === 'replace_block') {
1926 |                 // Strategy 1: Exact String Match (Fastest)
1927 |                 const currentStr = lines.join('\n');
1928 |                 if (currentStr.includes(op.find_block)) {
1929 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
1930 |                     logs.push('Exact match applied');
1931 |                     return;
1932 |                 }
1933 | 
1934 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
1935 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
1936 |                 if (searchLines.length === 0) return;
1937 | 
1938 |                 let matchStart = -1;
1939 |                 let matchEnd = -1;
1940 | 
1941 |                 // Scan file lines
1942 |                 for (let i = 0; i < lines.length; i++) {
1943 |                     // If first line matches (ignoring whitespace)
1944 |                     if (lines[i].trim() === searchLines[0]) {
1945 |                         // Check subsequent lines
1946 |                         let allMatch = true;
1947 |                         let fileOffset = 0;
1948 |                         let searchOffset = 1;
1949 |                         
1950 |                         while (searchOffset < searchLines.length) {
1951 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
1952 |                             const nextFile = lines[i + fileOffset + 1].trim();
1953 |                             // Skip empty lines in file if they aren't in search block
1954 |                             if (nextFile === '') {
1955 |                                 fileOffset++;
1956 |                                 continue;
1957 |                             }
1958 |                             if (nextFile !== searchLines[searchOffset]) {
1959 |                                 allMatch = false;
1960 |                                 break;
1961 |                             }
1962 |                             fileOffset++;
1963 |                             searchOffset++;
1964 |                         }
1965 | 
1966 |                         if (allMatch) {
1967 |                             matchStart = i;
1968 |                             matchEnd = i + fileOffset;
1969 |                             break;
1970 |                         }
1971 |                     }
1972 |                 }
1973 | 
1974 |                 if (matchStart !== -1) {
1975 |                     // Replace the range of lines
1976 |                     const replacement = op.replace_with.split('\n');
1977 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
1978 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
1979 |                 } else {
1980 |                     success = false;
1981 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
1982 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
1983 |                 }
1984 |             }
1985 |         });
1986 |         return { content: lines.join('\n'), success, logs };
1987 |     }
