3681 |         
3682 |         pathEl.innerText = path;
3683 |         msgEl.innerHTML = `<strong>Line ${error.line}, Col ${error.column || '?'}:</strong> ${error.message}`;
3684 |         codeEl.innerText = "Loading context...";
