3690 |             const res = await fetch(CONFIG.funcUrl, { 
3691 |                 method: 'POST', headers: {'Content-Type': 'application/json'}, 
3692 |                 body: apiBody({ action: 'preview_file', file_path: path }) 
3693 |             });
3694 |             const data = await res.json();
3695 |             const fullCode = b64DecodeUnicode(data.content || "");
3696 |             
3697 |             // Window: 5 lines before and after
3698 |             const lines = fullCode.split('\n');
3699 |             const start = Math.max(0, error.line - 6);
3700 |             const end = Math.min(lines.length, error.line + 5);
3701 |             
3702 |             let snippet = "";
3703 |             for (let i = start; i < end; i++) {
3704 |                 const lineNum = i + 1;
3705 |                 const marker = (lineNum === error.line) ? "> " : "  ";
3706 |                 snippet += `${marker}${lineNum.toString().padEnd(4)} | ${lines[i]}\n`;
3707 |             }
3708 |             
3709 |             codeEl.innerText = snippet;
3710 |             
3711 |             // Store for fix application
3712 |             currentSyntaxContext = { file: path, error: error, code: fullCode, ops: null };
3713 | 
3714 |             // Check for Deterministic Fix Availability
3715 |             checkDeterministicFix(path, error, fullCode);
3716 | 
3717 |         } catch(e) {
3718 |             codeEl.innerText = "Failed to load file content: " + e.message;
3719 |         }
