4643 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
4644 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
4645 |         
4646 |         const navItems = document.querySelectorAll('.nav-item');
4647 |         switchTab(tabId, navItems[navIndex]);
4648 | 
4649 |         const scrollContainer = document.querySelector('.main-view');
4650 |         let retryCount = 0;
4651 |         const MAX_RETRIES = 5;
4652 | 
4653 |         const attemptNavigation = async () => {
4654 |             const element = document.querySelector(selector);
4655 |             
4656 |             if (element) {
4657 |                 console.log("[DeepJump] Element found. Scrolling...");
4658 |                 
4659 |                 // Wait for any tab transition animations
4660 |                 await new Promise(r => setTimeout(r, 300));
4661 | 
4662 |                 let offsetTop = 0;
4663 |                 let curr = element;
4664 |                 while (curr && curr !== scrollContainer) {
4665 |                     offsetTop += curr.offsetTop;
4666 |                     curr = curr.offsetParent;
4667 |                 }
4668 | 
4669 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
4670 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
4671 | 
4672 |                 // Visual Highlight
4673 |                 element.style.transition = 'all 0.5s ease';
4674 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
4675 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
4676 |                 setTimeout(() => {
4677 |                     element.style.backgroundColor = '';
4678 |                     element.style.boxShadow = '';
4679 |                 }, 3000);
4680 |                 
4681 |                 console.groupEnd();
4682 |                 return true;
4683 |             }
4684 | 
4685 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
4686 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
4687 |                 retryCount++;
4688 |                 showGlobalToast("🔍 Searching deeper...");
4689 |                 
4690 |                 await loadMoreFn(); 
4691 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
4692 |                 return attemptNavigation();
4693 |             }
4694 | 
4695 |             console.error("[DeepJump] Failed: Element not found after retries.");
4696 |             showGlobalToast("Entry not found in recent history.", true);
4697 |             console.groupEnd();
4698 |             return false;
4699 |         };
4700 | 
4701 |         setTimeout(attemptNavigation, 100);
4702 |     }
