1991 |     async function runAutoFixLoop(name, code, errorList) {
1992 |         const status = document.getElementById('ef-status-msg');
1993 |         let currentCode = code;
1994 |         let currentErrors = errorList;
1995 | 
1996 |         // Fix one by one (recursive loop)
1997 |         async function fixNext(index) {
1998 |             if (index >= currentErrors.length) return true; // All initial errors processed
1999 | 
2000 |             const err = currentErrors[index];
2001 |             status.innerText = `🔧 Fixing Error ${index + 1}/${currentErrors.length} (Line ${err.line})...`;
2002 |             status.style.color = "#eab308"; // Dev yellow
2003 | 
2004 |             try {
2005 |                 // 1. Get Patch from AI
2006 |                 const res = await fetch(CONFIG.funcUrl, { 
2007 |                     method: 'POST', 
2008 |                     headers: {'Content-Type': 'application/json'},
2009 |                     body: apiBody({ 
2010 |                         action: 'propose_syntax_fix', 
2011 |                         code: currentCode, 
2012 |                         error: err 
2013 |                     })
2014 |                 });
2015 |                 const data = await res.json();
2016 |                 const ops = data.operations;
2017 | 
2018 |                 if (!ops || ops === "[]") throw new Error("AI could not generate a fix.");
2019 | 
2020 |                 // 2. Apply Patch Locally
2021 |                 const patchResult = applyLocalPatch(currentCode, ops);
2022 |                 if (!patchResult.success) throw new Error("Generated patch did not match code.");
2023 | 
2024 |                 currentCode = patchResult.content;
2025 |                 document.getElementById('ef-code').value = currentCode; // Update UI
2026 | 
2027 |                 // 3. Re-Validate
2028 |                 const scanRes = await fetch(CONFIG.funcUrl, { 
2029 |                     method: 'POST', headers: {'Content-Type': 'application/json'},
2030 |                     body: apiBody({ action: 'validate_syntax_deep', code_block: currentCode, file_path: 'index.ts' })
2031 |                 });
2032 |                 const scanData = await scanRes.json();
2033 | 
2034 |                 if (scanData.valid) {
2035 |                     status.innerText = "✅ Syntax Fixed!";
2036 |                     return true;
2037 |                 } else {
2038 |                     // If errors remain, update list and Prompt user
2039 |                     currentErrors = scanData.errors;
2040 |                     if (confirm(`Fix applied, but ${currentErrors.length} errors remain. Continue fixing?`)) {
2041 |                         // Recursively fix the *new* first error (since layout changed)
2042 |                         return await fixNext(0);
2043 |                     } else {
2044 |                         return false;
2045 |                     }
2046 |                 }
2047 | 
2048 |             } catch (e) {
2049 |                 if (confirm(`Auto-Fix Failed: ${e.message}\n\nTry again?`)) {
2050 |                     return await fixNext(index);
2051 |                 } else {
2052 |                     return false;
2053 |                 }
2054 |             }
2055 |         }
2056 | 
2057 |         return await fixNext(0);
2058 |     }
