4506 |     // --- GENERIC UI ---
4507 |     function formatBytes(bytes) {
4508 |         if (!bytes) return '0 B';
4509 |         const k = 1024;
4510 |         const sizes = ['B', 'KB', 'MB', 'GB'];
4511 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
4512 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
4513 |     }
