4515 |     function timeAgo(dateString) {
4516 |         const date = new Date(dateString);
4517 |         const now = new Date();
4518 |         const seconds = Math.floor((now - date) / 1000);
4519 |         if (seconds < 10) return 'just now';
4520 |         if (seconds < 60) return seconds + 's ago';
4521 |         const minutes = Math.floor(seconds / 60);
4522 |         if (minutes < 60) return minutes + 'm ago';
4523 |         const hours = Math.floor(minutes / 60);
4524 |         if (hours < 24) return hours + 'h ago';
4525 |         return date.toLocaleDateString();
4526 |     }
