5531 |         exportController = new AbortController();
5532 |         const signal = exportController.signal;
5533 | 
5534 |         try {
5535 |             const fetchedFiles = [];
5536 |             const BATCH_SIZE = 8; // Optimal balance for browser concurrency and API stability
5537 |             
5538 |             for (let i = 0; i < checked.length; i += BATCH_SIZE) {
5539 |                 if (signal.aborted) throw new Error("Cancelled by user");
5540 | 
5541 |                 const batch = checked.slice(i, i + BATCH_SIZE);
5542 |                 statusEl.innerText = `⚡ Parallel Fetching: ${i + 1}-${Math.min(i + BATCH_SIZE, checked.length)} of ${checked.length}...`;
5543 |                 statusEl.style.color = "var(--ai-accent)";
5544 | 
5545 |                 const batchResults = await Promise.all(batch.map(async (path) => {
5546 |                     const res = await fetch(CONFIG.funcUrl, {
5547 |                         method: 'POST',
5548 |                         headers: { 'Content-Type': 'application/json' },
5549 |                         body: apiBody({ action: 'preview_file', file_path: path }),
5550 |                         signal: signal 
5551 |                     });
5552 |                     const data = await res.json();
5553 |                     if (!data.content) return null;
5554 |                     return { path, content: b64DecodeUnicode(data.content) };
5555 |                 }));
5556 | 
5557 |                 fetchedFiles.push(...batchResults.filter(f => f !== null));
5558 |             }
5559 | 
5560 |             statusEl.innerText = "📦 Finalizing Bundle...";
5561 | 
5562 |             const ts = new Date().toLocaleTimeString('en-GB').replace(/:/g, '');
5563 |             const finalBaseName = `${CONFIG.repoName}_${ts}`;
5564 | 
5565 |             if (type === 'zip') {
5566 |                 const zip = new JSZip();
5567 |                 fetchedFiles.forEach(f => zip.file(f.path, f.content));
5568 |                 const blob = await zip.generateAsync({ type: "blob" });
5569 |                 const link = document.createElement('a');
5570 |                 link.href = URL.createObjectURL(blob);
5571 |                 link.download = `${finalBaseName}.zip`;
5572 |                 link.click();
5573 |             } else {
5574 |                 const text = fetchedFiles.map(f => `FILE: ${f.path}\n${f.content}`).join('\n\n');
5575 |                 const link = document.createElement('a');
5576 |                 link.href = URL.createObjectURL(new Blob([text], { type: "text/plain" }));
5577 |                 link.download = `${finalBaseName}.txt`;
5578 |                 link.click();
5579 |             }
5580 |             
5581 |             if (!signal.aborted) {
5582 |                 document.getElementById('export-modal').style.display = 'none';
5583 |             }
5584 |         } catch (e) {
5585 |             if (e.message === "Cancelled by user" || e.name === 'AbortError') {
5586 |                 statusEl.innerText = "Cancelled.";
5587 |                 statusEl.style.color = "var(--text-muted)";
5588 |             } else {
5589 |                 statusEl.innerText = "Error: " + e.message;
5590 |                 statusEl.style.color = "var(--danger)";
