6577 |                 // Escape quotes and wrap in quotes
6578 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
6579 |             }).join(',')
6580 |         );
6581 |         return [headers.join(','), ...rows].join('\n');
6582 |     }
